/**
 * Zod schemas for YAML frontmatter metadata in generated documents
 *
 * Defines the structure for frontmatter that is prepended to
 * all documents generated by the AD-SDLC pipeline (PRD, SRS, SDS).
 *
 * @module schemas/document-frontmatter
 */

import { z } from 'zod';

/**
 * Document types generated by the AD-SDLC pipeline
 */
export const DocumentTypeSchema = z.enum(['PRD', 'SRS', 'SDS']);
export type DocumentType = z.infer<typeof DocumentTypeSchema>;

/**
 * Document status values
 */
export const DocumentStatusSchema = z.enum(['Draft', 'Review', 'Approved']);
export type DocumentStatus = z.infer<typeof DocumentStatusSchema>;

/**
 * Approval entry in frontmatter
 */
export const ApprovalEntrySchema = z.object({
  role: z.string(),
  name: z.string().optional(),
  date: z.string().optional(),
  status: z.enum(['pending', 'approved', 'rejected']),
});
export type ApprovalEntry = z.infer<typeof ApprovalEntrySchema>;

/**
 * Change history entry in frontmatter
 */
export const ChangeHistoryEntrySchema = z.object({
  version: z.string(),
  date: z.string(),
  author: z.string(),
  description: z.string(),
});
export type ChangeHistoryEntry = z.infer<typeof ChangeHistoryEntrySchema>;

/**
 * Complete YAML frontmatter schema for generated documents
 */
export const DocumentFrontmatterSchema = z.object({
  doc_id: z.string(),
  title: z.string(),
  version: z.string(),
  status: DocumentStatusSchema,
  generated_by: z.string(),
  generated_at: z.string(),
  pipeline_session: z.string().optional(),
  source_documents: z.array(z.string()).optional(),
  approval: z.array(ApprovalEntrySchema).optional(),
  change_history: z.array(ChangeHistoryEntrySchema).optional(),
});
export type DocumentFrontmatter = z.infer<typeof DocumentFrontmatterSchema>;
